form:Form.form:Scripts:
		function DownloadTXT()
{
	DownloadFile("INTERFACES\\" + Ctrl("batch").GetXValue() + ".txt", Ctrl("batch").GetXValue() + ".txt");
}                   

function DownloadXLS()
{
	DownloadFile("INTERFACES\\" + Ctrl("batch").GetXValue() + ".txt", Ctrl("batch").GetXValue() + ".csv");
}         


function EnableBack()
{       
	CtrlEnabled('BACK', true);       
	CtrlEnabled('DOWNLOADTXT', true);
	CtrlEnabled('DOWNLOADXLS', true);
}

function LoadForm()
{ 
	if( Ctrl('main').GetMode() == "BATCH" )    
	{                                 
		CtrlEnabled('BACK', true);
		CtrlEnabled('DOWNLOADTXT', true);
		CtrlEnabled('DOWNLOADXLS', true);
	}

}
